"""Shared DevPod CLI step runner for provider bootstrap modules."""

from __future__ import annotations

from collections.abc import Sequence
from dataclasses import dataclass
from typing import Protocol


class BootstrapError(Exception):
    """Raised when DevPod bootstrap cannot complete."""


@dataclass(frozen=True, slots=True)
class CliRunResult:
    returncode: int
    stderr: str = ""


class DevpodCliRunner(Protocol):
    def __call__(self, argv: Sequence[str]) -> CliRunResult: ...


def run_step(
    label: str,
    argv: Sequence[str],
    runner: DevpodCliRunner,
) -> None:
    """Run a labelled devpod CLI step; raise BootstrapError on non-zero exit."""
    result = runner(argv)
    if result.returncode != 0:
        detail = result.stderr or f"exit code {result.returncode}"
        raise BootstrapError(f"{label} failed: {detail}")

